import numpy as np

def calculate_distance(pos1, pos2):
    return np.linalg.norm(pos1 - pos2)

def calculate_arrival_time(cur_pos, dest_pos, current_time, truck_speed):
    distance = calculate_distance(cur_pos, dest_pos)
    travel_time = distance / truck_speed
    return current_time + travel_time

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_score = float('inf')
    best_node = None

    for idx, customer_pos in enumerate(unvisited_customers):
        arrival_time = calculate_arrival_time(cur_truck_pos, customer_pos, current_time, truck_speed)
        start_tw, end_tw = time_windows[idx]

        if arrival_time > end_tw:
            score = float('inf')  # large penalty for missing the time window
        else:
            wait_time = max(0, start_tw - arrival_time)
            score = wait_time + (end_tw - current_time)  # prioritize early stops within window

        # Update the best choice
        if score < best_score:
            best_score = score
            best_node = idx

    # If no valid node is found, decide to wait
    if best_node is None or best_score == float('inf'):
        best_node = None

    return best_node
